+import { Added, Changed, createAdded, createChanged, createPredicate, createRemoved, createWorld, Not, Or, relation, trait } from '../src';
+import { describe, expect, it } from 'vitest';
+
+describe('predicates', () => {
+    it('filters values and re-evaluates on add and set', () => {
+        const Position = trait({ x: 0 });
+        const Positive = createPredicate([Position], ([position]) => position.x > 0);
+        const world = createWorld();
+        const entity = world.spawn(Position({ x: -1 }));
+        expect(world.query(Positive)).toEqual([]);
+        entity.set(Position, { x: 1 });
+        expect(world.query(Positive)).toEqual([entity]);
+        entity.set(Position, { x: -1 });
+        expect(world.query(Positive)).toEqual([]);
+    });
+
+    it('supports Not, Or, relations, and does not expose dependency data', () => {
+        const Position = trait({ x: 0 });
+        const Name = trait({ value: '' });
+        const ChildOf = relation();
+        const Positive = createPredicate([Position], ([position]) => position.x > 0);
+        const world = createWorld();
+        const parent = world.spawn();
+        const child = world.spawn(Position({ x: 1 }), Name({ value: 'a' }), ChildOf(parent));
+        expect(world.query(Not(Positive))).toEqual([parent]);
+        expect(world.query(Or(Positive), ChildOf(parent))).toEqual([child]);
+        world.query(Positive, Name).readEach((state) => expect(state).toEqual([{ value: 'a' }]));
+    });
+
+    it('tracks predicate truth transitions', () => {
+        const Position = trait({ x: 0 });
+        const Positive = createPredicate([Position], ([position]) => position.x > 0);
+        const Added = createAdded();
+        const Removed = createRemoved();
+        const Changed = createChanged();
+        const world = createWorld();
+        const entity = world.spawn(Position({ x: -1 }));
+        entity.set(Position, { x: 1 });
+        expect(world.query(Added(Positive))).toEqual([entity]);
+        entity.set(Position, { x: -1 });
+        expect(world.query(Removed(Positive))).toEqual([entity]);
+        entity.set(Position, { x: 1 });
+        expect(world.query(Changed(Positive))).toEqual([entity]);
+    });
+
+    it('rejects tags and relations as dependencies', () => {
+        const Tag = trait();
+        const Relation = relation();
+        expect(() => createPredicate([Tag], () => true)).toThrow();
+        expect(() => createPredicate([Relation as never], () => true)).toThrow();
+    });
+});
